function Counter() {
  const count = useRef(0);

  function add() {
    count.current = count.current + 1;
    console.log(count.current);   // 有變大！
  }

  return <button onClick={add}>{count.current}</button>;
}

function Cart() {
  const count = useRef(0);           // A 行

  function addItem() {
    count.current += 1;
  }

  return (
    <div>
      <span>購物車（{count.current}）</span>
      <button onClick={addItem}>加入</button>
    </div>
  );
}

